// 세로 스크롤 진행률 → 가로 이동량
var st = document.querySelector(".scroll-track");
var stage = document.querySelector(".sticky-stage");
var track = document.querySelector(".track");
var cards = document.querySelectorAll(".card");
function progress(){
  var r = st.getBoundingClientRect();
  var max = Math.max(1, r.height - innerHeight);
  return Math.min(1, Math.max(0, -r.top / max));
}
function maxX(){ return Math.max(0, track.scrollWidth - stage.clientWidth); }

function applyMove(p){
  track.style.transform = "translateX(" + (-maxX() * p) + "px)";
}

// smooth scroll — 실제 스크롤(target)을 current가 lerp로 부드럽게 추격
